"use client";

import Link from "next/link";
import { FormEvent, useState } from "react";

type AuthMode = "login" | "register";

type AuthCardProps = {
  mode: AuthMode;
};

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function AuthCard({ mode }: AuthCardProps) {
  const isRegister = mode === "register";
  const [lastName, setLastName] = useState("");
  const [firstName, setFirstName] = useState("");
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState("");
  const [messageType, setMessageType] = useState<"ok" | "error">("ok");

  const handleSubmit = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    if (!username.trim() || !password.trim()) {
      setMessageType("error");
      setMessage("Vui lòng nhập đầy đủ số điện thoại và mật khẩu.");
      return;
    }

    if (isRegister) {
      if (!lastName.trim() || !firstName.trim()) {
        setMessageType("error");
        setMessage("Vui lòng nhập đầy đủ họ và tên.");
        return;
      }

      if (!email.trim()) {
        setMessageType("error");
        setMessage("Vui lòng nhập email.");
        return;
      }

      if (!emailRegex.test(email.trim())) {
        setMessageType("error");
        setMessage("Email không đúng định dạng.");
        return;
      }

      if (!confirmPassword.trim()) {
        setMessageType("error");
        setMessage("Vui lòng nhập xác nhận mật khẩu.");
        return;
      }

      if (password !== confirmPassword) {
        setMessageType("error");
        setMessage("Mật khẩu xác nhận không khớp.");
        return;
      }
    }

    setMessageType("ok");
    setMessage(
      isRegister
        ? "Đăng ký thành công (demo UI)."
        : "Đăng nhập thành công (demo UI)."
    );
  };

  return (
    <main className="auth-shell">
      <section className="auth-panel">
        <div className="card">
          <div className="card-head">
            <h2>{isRegister ? "Đăng ký tài khoản" : "Đăng nhập"}</h2>
            <p>
              {isRegister
                ? "Tạo tài khoản mới để bắt đầu trò chuyện"
                : "Chào mừng bạn quay trở lại Food Web"}
            </p>
          </div>

          <div className="tabs">
            <Link href="/login" className={!isRegister ? "tab active" : "tab"}>
              Đăng nhập
            </Link>
            <Link href="/register" className={isRegister ? "tab active" : "tab"}>
              Đăng ký
            </Link>
          </div>

          <form onSubmit={handleSubmit} className="form-grid">
            {isRegister && (
              <div className="name-row">
                <label className="field">
                  <span>Họ</span>
                  <div className="input-wrap">
                    <input
                      type="text"
                      value={lastName}
                      onChange={(event) => setLastName(event.target.value)}
                      placeholder="Nhập họ"
                      autoComplete="family-name"
                    />
                  </div>
                </label>

                <label className="field">
                  <span>Tên</span>
                  <div className="input-wrap">
                    <input
                      type="text"
                      value={firstName}
                      onChange={(event) => setFirstName(event.target.value)}
                      placeholder="Nhập tên"
                      autoComplete="given-name"
                    />
                  </div>
                </label>
              </div>
            )}

            <label className="field">
              <span>Số điện thoại</span>
              <div className="phone-wrap">
                <span className="phone-prefix">+84</span>
                <input
                  type="text"
                  value={username}
                  onChange={(event) => setUsername(event.target.value)}
                  placeholder="Nhập số điện thoại"
                  autoComplete="username"
                />
              </div>
            </label>

            {isRegister && (
              <label className="field">
                <span>Email</span>
                <div className="input-wrap">
                  <input
                    type="email"
                    value={email}
                    onChange={(event) => setEmail(event.target.value)}
                    placeholder="Nhập email"
                    autoComplete="email"
                  />
                </div>
              </label>
            )}

            <label className="field">
              <span>Mật khẩu</span>
              <div className="input-wrap">
                <input
                  type="password"
                  value={password}
                  onChange={(event) => setPassword(event.target.value)}
                  placeholder="Nhập mật khẩu"
                  autoComplete={isRegister ? "new-password" : "current-password"}
                />
              </div>
            </label>

            {isRegister && (
              <label className="field">
                <span>Xác nhận mật khẩu</span>
                <div className="input-wrap">
                  <input
                    type="password"
                    value={confirmPassword}
                    onChange={(event) => setConfirmPassword(event.target.value)}
                    placeholder="Nhập lại mật khẩu"
                    autoComplete="new-password"
                  />
                </div>
              </label>
            )}

            <button type="submit" className="submit-btn">
              {isRegister ? "Đăng ký" : "Đăng nhập"}
            </button>

            {message ? (
              <p className={messageType === "ok" ? "message ok" : "message error"}>
                {message}
              </p>
            ) : null}
          </form>
        </div>
      </section>
    </main>
  );
}
